    comment_id, content, content_preview, audit_status, created_at, updated_at
) VALUES (
    #{commentId}, #{content}, #{contentPreview}, #{auditStatus}, #{createdAt}, #{updatedAt}
)

mapper.select:
SELECT comment_id, content, content_preview, audit_status, created_at, updated_at
FROM bluenote_comment.comment_content
WHERE comment_id = #{commentId}
